// Anthropic node may return content[0].text (raw API) or text (native node)
const rawText = (
  $input.item.json?.content?.[0]?.text ??
  $input.item.json?.text ??
  $input.item.json?.message ??
  $input.item.json?.output
);
if (!rawText) throw new Error('No text output from Anthropic node. Input: ' + JSON.stringify($input.item.json));

let configJson;
try {
  const cleaned = rawText
    .replace(/^```(?:json)?\s*/i, '')
    .replace(/\s*```$/, '')
    .trim();
  configJson = JSON.parse(cleaned);
} catch (e) {
  throw new Error('CONFIG_PARSE_FAILED: ' + rawText);
}

// --- Auto-fill fields Claude sometimes omits ---

// Pricing tiers
if (Array.isArray(configJson.pricing)) {
  for (const tier of configJson.pricing) {
    if (!tier.cta_text) tier.cta_text = 'Get Started';
    if (!tier.cta_url) tier.cta_url = '/contact';
    if (tier.is_featured === undefined) tier.is_featured = false;
    if (!tier.billing_period) tier.billing_period = '/mo';
    if (!Array.isArray(tier.features)) tier.features = [];
  }
}

// Footer social links
if (configJson.content && configJson.content.footer && !Array.isArray(configJson.content.footer.social_links)) {
  configJson.content.footer.social_links = [];
}

// Nullable URL fields
if (configJson.map_embed_url === undefined) configJson.map_embed_url = null;
if (configJson.brand && configJson.brand.logo_url === undefined) configJson.brand.logo_url = null;

// Force team photos to null — avatar placeholder is better than fake headshots
if (Array.isArray(configJson.team)) {
  for (const member of configJson.team) {
    member.photo_url = null;
  }
}

// Force hero background to null — Unsplash node will inject a real image
if (configJson.content && configJson.content.hero) {
  configJson.content.hero.background_image_url = null;
}

// --- End auto-fill ---

if (!configJson.client?.slug) {
  throw new Error('CONFIG_PARSE_FAILED: Missing client.slug in generated config');
}

const clientSlug = configJson.client.slug;
const configJsonStr = JSON.stringify(configJson, null, 2);
const configJsonB64 = Buffer.from(configJsonStr).toString('base64');

const tallyData = $('Build Pipeline Transform').first().json;

// Use Claude-generated image search query, fall back to first service title
const searchQuery = configJson.image_search_query
  || (configJson.services?.[0]?.title ?? 'professional business');

return [{
  json: {
    config_json: configJson,
    config_json_b64: configJsonB64,
    client_slug: clientSlug,
    business_name: tallyData.business_name,
    tier: tallyData.tier || 1,
    unsplash_query: searchQuery
  }
}];

// Inject Unsplash hero image URL into config, re-encode base64.
// If Unsplash call failed, fall back gracefully (hero renders CSS gradient).

const prev = $('Parse and Validate Config JSON').first().json;
const configJson = JSON.parse(JSON.stringify(prev.config_json));

// Try to extract URL from Unsplash response
const unsplashResults = $input.item.json?.results;
const heroUrl = (Array.isArray(unsplashResults) && unsplashResults.length > 0)
  ? unsplashResults[0].urls?.regular ?? unsplashResults[0].urls?.full ?? null
  : null;

if (heroUrl && configJson.content && configJson.content.hero) {
  configJson.content.hero.background_image_url = heroUrl;
}

const configJsonStr = JSON.stringify(configJson, null, 2);
const configJsonB64 = Buffer.from(configJsonStr).toString('base64');

return [{
  json: {
    ...prev,
    config_json: configJson,
    config_json_b64: configJsonB64
  }
}];

