// NEW Transform node for Build Pipeline — replaces the old Tally parser.
// Receives data forwarded from the Website Intake workflow.
// Input: $json.body.* (intake form fields) — same structure as the intake webhook.
// Output: flat fields matching what the rest of the Build Pipeline expects.

const input = $input.item.json.body ?? $input.item.json;

const packageMap = {
  'starter':   { pages: ['home', 'contact'], tier: 1, label: 'Starter' },
  'full-site': { pages: ['home', 'services', 'about', 'contact', 'pricing', 'faq'], tier: 1, label: 'Full Site' },
  'tier-2':    { pages: ['home', 'services', 'about', 'contact', 'pricing', 'faq'], tier: 2, label: 'Tier 2' },
};

const pkg = packageMap[input.packageTier] ?? packageMap['starter'];

return [{ json: {
  business_name:     input.businessName,
  business_url:      input.businessUrl || null,
  business_phone:    input.businessPhone,
  business_address:  input.businessAddress,
  business_city:     input.businessCity,
  business_state:    input.businessState,
  primary_color:     input.primaryColor || null,
  secondary_color:   input.secondaryColor || null,
  tagline:           input.tagline || null,
  package:           pkg.label,
  pages_needed:      pkg.pages,
  tier:              pkg.tier,
  appointment_url:   input.bookingLink || null,
  payment_url:       input.paymentLink || null,
  google_review_url: input.googleReviewUrl || null,
  notes:             input.additionalNotes || null,
}}];
